<?php
 namespace WPAICG\Vector\Providers\Pinecone\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_Pinecone_Strategy; use WP_Error; if (!defined('ABSPATH')) { exit; } function connect_logic(AIPKit_Vector_Pinecone_Strategy $strategyInstance, array $config): bool|WP_Error { if (empty($config['api_key'])) { return new WP_Error('missing_api_key_pinecone', __('Pinecone API Key is required.', 'gpt3-ai-content-generator')); } $strategyInstance->set_api_key($config['api_key']); $strategyInstance->set_is_connected_status(true); $test_list_response = $strategyInstance->list_indexes(1); if (is_wp_error($test_list_response)) { $strategyInstance->set_is_connected_status(false); return $test_list_response; } return true; }